catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading) return;

    // جمع كل الـ rows الموجودة في الـ Variable Set
    // اسم الـ variable بتاع الدواء جوا الـ Set — غيّريه لو مختلف
    var MEDICINE_VAR_NAME = 'medicine_name'; // اسم الـ reference field جوا الـ set

    var seenIds    = [];   // هنحط فيه الـ sys_id بتاع كل دواء
    var hasDuplicate = false;
    var duplicateName = '';

    // الـ Multi-Row Variable Set بيولّد fields باسم زي:
    // IO:medicine_name_0, IO:medicine_name_1, IO:medicine_name_2 ...
    // نلف عليهم
    var rowIndex = 0;
    while (true) {
        var fieldName = 'IO:' + MEDICINE_VAR_NAME + '_' + rowIndex;
        var el = gel(fieldName);           // gel = getElementById في ServiceNow
        if (!el) break;                    // وصلنا لآخر row موجود

        var val = g_form.getValue(fieldName);
        if (val && val !== '') {
            if (seenIds.indexOf(val) !== -1) {
                // تكرار!
                hasDuplicate  = true;
                duplicateName = g_form.getDisplayValue(fieldName);
                // امسح القيمة اللي اتضافت دلوقتي
                g_form.setValue(fieldName, '');
                g_form.clearMessages();
                g_form.addErrorMessage(
                    '⚠ "' + duplicateName + '" is already in your order. ' +
                    'Please update the quantity in the existing row instead.'
                );
                break;
            } else {
                seenIds.push(val);
            }
        }
        rowIndex++;
    }
}
